-- סגירת החתמות ישנות שנשארו פתוחות
UPDATE attendance
SET clock_out = clock_in + interval '8 hours'
WHERE clock_out IS NULL
  AND clock_in < '2026-07-15T00:00:00+03';

-- שיבוצי משמרת להיום
ON CONFLICT (employee_id, shift_date, shift_template_id) DO NOTHING;

